import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly handling user input by encoding it before outputting it to the response
        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println("<html>");
            out.println("<body>");
            out.println("<h1>Welcome, " + ESAPI.encoder().encodeForHTML(userInput) + "</h1>");
            out.println("</body>");
            out.println("</html>");
            out.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
